@@ -2590,11 +2590,13 @@ void empty_curbuf(...)
   win_init_empty(curwin);
 }

-/// Closes all windows for buffer `buf` unless there is only one non-floating window.
+/// Closes all windows for buffer `buf` unless there is only one non-floating
+/// window. Returns the curtab non-float that still shows `buf` (the "holder"
+/// the loop refused to close), or NULL.
 ///
 /// @param keep_curwin  don't close `curwin`
-void close_windows(buf_T *buf, bool keep_curwin)
+win_T *close_windows(buf_T *buf, bool keep_curwin)
 {
   RedrawingDisabled++;

   // Start from lastwin to close floating windows with the same buffer first.
@@ -2643,8 +2645,17 @@ void close_windows(buf_T *buf, bool keep_curwin)
     }
   }

 theend:
   RedrawingDisabled--;
+
+  // If the main loop bailed because the last non-float showed `buf`, surface
+  // it so the caller can decide whether to retry the operation from there.
+  FOR_ALL_WINDOWS_IN_TAB(wp, curtab) {
+    if (wp->w_buffer == buf && !wp->w_floating) {
+      return wp;
+    }
+  }
+  return NULL;
 }

